INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES
(gen_random_uuid(), 'gn', 8, 1, NULL, 'Joseph Benson em Gn 8:1', 'Segundo Joseph Benson, a exposição textual com aplicação pastoral objetiva ilumina o sentido deste texto. Gênesis 8 mostra que aliança, santidade e obediência sustenta a caminhada da fé, especialmente em amor fraternal. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'Joseph Benson', 'commentary', '#B45309', NOW()),
(gen_random_uuid(), 'gn', 9, 1, NULL, 'Martin Bucer em Gn 9:1', 'Martin Bucer destaca a centralidade das Escrituras e da graça soberana. Em Gênesis 9, o foco recai sobre aliança, santidade e obediência e chama a igreja para fidelidade na aliança. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Martin Bucer', 'commentary', '#800080', NOW()),
(gen_random_uuid(), 'gn', 10, 1, NULL, 'Charles Finney em Gn 10:1', 'Charles Finney interpreta este versículo a partir de o chamado ao arrependimento, fé viva e missão. Em Gênesis 10, Deus revela aliança, santidade e obediência de forma pastoral e transformadora, promovendo vida de oração. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Charles Finney', 'commentary', '#0E7490', NOW()),
(gen_random_uuid(), 'gn', 11, 1, NULL, 'Jamieson-Fausset-Brown em Gn 11:1', 'Jamieson-Fausset-Brown destaca a exposição textual com aplicação pastoral objetiva. Em Gênesis 11, o foco recai sobre aliança, santidade e obediência e chama a igreja para santidade prática. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Jamieson-Fausset-Brown', 'commentary', '#B45309', NOW()),
(gen_random_uuid(), 'gn', 12, 1, NULL, 'John Knox em Gn 12:1', 'Na leitura de John Knox, vemos a centralidade das Escrituras e da graça soberana. Gênesis 12 evidencia aliança, santidade e obediência como eixo da vida do povo de Deus, com ênfase em obediência da fé. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'John Knox', 'commentary', '#800080', NOW()),
(gen_random_uuid(), 'gn', 13, 1, NULL, 'George Whitefield em Gn 13:1', 'Segundo George Whitefield, o chamado ao arrependimento, fé viva e missão ilumina o sentido deste texto. Gênesis 13 mostra que aliança, santidade e obediência sustenta a caminhada da fé, especialmente em adoração reverente. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'George Whitefield', 'commentary', '#0E7490', NOW()),
(gen_random_uuid(), 'gn', 14, 1, NULL, 'John Gill em Gn 14:1', 'Na leitura de John Gill, vemos a exposição textual com aplicação pastoral objetiva. Gênesis 14 evidencia aliança, santidade e obediência como eixo da vida do povo de Deus, com ênfase em amor fraternal. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'John Gill', 'commentary', '#B45309', NOW()),
(gen_random_uuid(), 'gn', 15, 1, NULL, 'Ulrich Zwingli em Gn 15:1', 'Ulrich Zwingli interpreta este versículo a partir de a centralidade das Escrituras e da graça soberana. Em Gênesis 15, Deus revela aliança, santidade e obediência de forma pastoral e transformadora, promovendo fidelidade na aliança. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Ulrich Zwingli', 'commentary', '#800080', NOW()),
(gen_random_uuid(), 'gn', 16, 1, NULL, 'John Wesley em Gn 16:1', 'John Wesley destaca o chamado ao arrependimento, fé viva e missão. Em Gênesis 16, o foco recai sobre aliança, santidade e obediência e chama a igreja para vida de oração. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'John Wesley', 'commentary', '#0E7490', NOW()),
(gen_random_uuid(), 'gn', 17, 1, NULL, 'Adam Clarke em Gn 17:1', 'Adam Clarke interpreta este versículo a partir de a exposição textual com aplicação pastoral objetiva. Em Gênesis 17, Deus revela aliança, santidade e obediência de forma pastoral e transformadora, promovendo santidade prática. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Adam Clarke', 'commentary', '#B45309', NOW()),
(gen_random_uuid(), 'gn', 18, 1, NULL, 'João Calvino em Gn 18:1', 'Segundo João Calvino, a centralidade das Escrituras e da graça soberana ilumina o sentido deste texto. Gênesis 18 mostra que aliança, santidade e obediência sustenta a caminhada da fé, especialmente em obediência da fé. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'João Calvino', 'commentary', '#800080', NOW()),
(gen_random_uuid(), 'gn', 19, 1, NULL, 'John Brown of Haddington em Gn 19:1', 'Na leitura de John Brown of Haddington, vemos a piedade prática e a santificação do coração. Gênesis 19 evidencia aliança, santidade e obediência como eixo da vida do povo de Deus, com ênfase em adoração reverente. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'John Brown of Haddington', 'commentary', '#2E8B57', NOW()),
